 1	import * as React from 'react';
 2	import { useGetExternalClusterDetails } from '@odf/core/redux/utils';
 3	import { GraphEmpty } from '@odf/shared/charts';
 4	import { PrometheusUtilizationItem } from '@odf/shared/dashboards/utilization-card/prometheus-utilization-item';
 5	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 6	import { humanizeBinaryBytes } from '@odf/shared/utils';
 7	import { ByteDataTypes } from '@openshift-console/dynamic-plugin-sdk/lib/api/internal-types';
 8	import {
 9	  UtilizationDurationDropdown,
10	  UtilizationBody,
11	} from '@openshift-console/dynamic-plugin-sdk-internal';
12	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
13	import { useStorageClassQueryFilter } from '../../hooks';
14	import {
15	  StorageDashboardQuery,
16	  INDEPENDENT_UTILIZATION_QUERIES,
17	} from '../../queries';
18	
19	export const UtilizationContent: React.FC = () => {
20	  const { t } = useCustomTranslation();
21	
22	  const { clusterNamespace: clusterNs } = useGetExternalClusterDetails();
23	
24	  const [scQueryfilter, scQueryfilterLoaded, scQueryfilterError] =
25	    useStorageClassQueryFilter(clusterNs);
26	
27	  return (
28	    <UtilizationBody>
29	      {scQueryfilterLoaded && !scQueryfilterError && (
30	        <>
31	          <PrometheusUtilizationItem
32	            title={t('Used capacity')}
33	            utilizationQuery={
34	              INDEPENDENT_UTILIZATION_QUERIES(scQueryfilter)[
35	                StorageDashboardQuery.USED_CAPACITY
36	              ]
37	            }
38	            humanizeValue={humanizeBinaryBytes}
39	            byteDataType={ByteDataTypes.BinaryBytes}
40	          />
41	          <PrometheusUtilizationItem
42	            title={t('Requested capacity')}
43	            utilizationQuery={
44	              INDEPENDENT_UTILIZATION_QUERIES(scQueryfilter)[
45	                StorageDashboardQuery.REQUESTED_CAPACITY
46	              ]
47	            }
48	            humanizeValue={humanizeBinaryBytes}
49	            byteDataType={ByteDataTypes.BinaryBytes}
50	          />
51	        </>
52	      )}
53	      {!scQueryfilterLoaded && !scQueryfilterError && <GraphEmpty loading />}
54	      {!!scQueryfilterError && <GraphEmpty />}
55	    </UtilizationBody>
56	  );
57	};
58	
59	export const UtilizationCard: React.FC = () => {
60	  const { t } = useCustomTranslation();
61	  return (
62	    <Card>
63	      <CardHeader
64	        actions={{
65	          actions: <UtilizationDurationDropdown />,
66	          hasNoOffset: false,
67	          className: undefined,
68	        }}
69	      >
70	        <CardTitle>{t('Utilization')}</CardTitle>
71	      </CardHeader>
72	      <CardBody>
73	        <UtilizationContent />
74	      </CardBody>
75	    </Card>
76	  );
77	};
78	
79	export default UtilizationCard;

